private void xrTableCell52_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    // --- Declare values ---
decimal softShellEggs = 0;
decimal minorCrackedEggs = 0;
decimal majorCrackedEggs = 0;
decimal thinShellEggs = 0;
decimal otherEggs = 0;
decimal wholeEggs = 0;
decimal brokenEggs = 0;
decimal smallEggs = 0;
decimal overWeightEggs = 0;
decimal dirtyEggs = 0;
decimal deformityEggs = 0;
decimal crackedEggs = 0;
decimal doubleYolkEggs = 0;
decimal TotalSpecialEggs  = 0 ;
decimal Total = 0 ;
decimal TotalPercReport  =0;
// --- Read values ---
if (GetCurrentColumnValue("SoftShellEggs") != null)
    softShellEggs = Convert.ToDecimal(GetCurrentColumnValue("SoftShellEggs"));

if (GetCurrentColumnValue("MinorCrackedEggs") != null)
    minorCrackedEggs = Convert.ToDecimal(GetCurrentColumnValue("MinorCrackedEggs"));

if (GetCurrentColumnValue("MajorCrackedEggs") != null)
    majorCrackedEggs = Convert.ToDecimal(GetCurrentColumnValue("MajorCrackedEggs"));

if (GetCurrentColumnValue("ThinShellEggs") != null)
    thinShellEggs = Convert.ToDecimal(GetCurrentColumnValue("ThinShellEggs"));

if (GetCurrentColumnValue("OtherEggs") != null)
    otherEggs = Convert.ToDecimal(GetCurrentColumnValue("OtherEggs"));

if (GetCurrentColumnValue("WholeEggs") != null)
    wholeEggs = Convert.ToDecimal(GetCurrentColumnValue("WholeEggs"));

if (GetCurrentColumnValue("BrokenEggs") != null)
    brokenEggs = Convert.ToDecimal(GetCurrentColumnValue("BrokenEggs"));

if (GetCurrentColumnValue("SmallEggs") != null)
    smallEggs = Convert.ToDecimal(GetCurrentColumnValue("SmallEggs"));

if (GetCurrentColumnValue("OverWeightEggs") != null)
    overWeightEggs = Convert.ToDecimal(GetCurrentColumnValue("OverWeightEggs"));

if (GetCurrentColumnValue("DirtyEggs") != null)
    dirtyEggs = Convert.ToDecimal(GetCurrentColumnValue("DirtyEggs"));

if (GetCurrentColumnValue("DeformityEggs") != null)
    deformityEggs = Convert.ToDecimal(GetCurrentColumnValue("DeformityEggs"));

if (GetCurrentColumnValue("CrackedEggs") != null)
    crackedEggs = Convert.ToDecimal(GetCurrentColumnValue("CrackedEggs"));

if (GetCurrentColumnValue("DoubleYolkEggs") != null)
    doubleYolkEggs = Convert.ToDecimal(GetCurrentColumnValue("DoubleYolkEggs"));

// --- Sum them ---
decimal result = softShellEggs + minorCrackedEggs + majorCrackedEggs + thinShellEggs +
                 otherEggs + wholeEggs + brokenEggs + smallEggs + overWeightEggs +
                 dirtyEggs + deformityEggs + crackedEggs + doubleYolkEggs;

// --- Add to group total ---
Total += result;


// --- Add IIf logic ---
if (recEggs != 0)
    TotalPerc = (totalUnHatch * 100.0m / recEggs);

TotalPercReport += TotalPerc 


TotalSpecialEggs = result + TotalPerc 
TotalSpecialEggsReport = Total  + TotalPercReport 
// --- Assign result to cell ---
XRTableCell cell = sender as XRTableCell;
cell.Text = TotalSpecialEggs.ToString("0"); // no decimals

}

private void Detail_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    // --- Declare values ---
decimal softShellEggs = 0;
decimal minorCrackedEggs = 0;
decimal majorCrackedEggs = 0;
decimal thinShellEggs = 0;
decimal otherEggs = 0;
decimal wholeEggs = 0;
decimal brokenEggs = 0;
decimal smallEggs = 0;
decimal overWeightEggs = 0;
decimal dirtyEggs = 0;
decimal deformityEggs = 0;
decimal crackedEggs = 0;
decimal doubleYolkEggs = 0;
decimal destroyedEggs = 0;

decimal totalUnHatch = 0;
decimal recEggs = 0;

decimal groupSumSpecialEggs  =  0;
decimal TotalPercGroup  = 0 ;
// --- Read values ---
if (GetCurrentColumnValue("SoftShellEggs") != null)
    softShellEggs = Convert.ToDecimal(GetCurrentColumnValue("SoftShellEggs"));

if (GetCurrentColumnValue("MinorCrackedEggs") != null)
    minorCrackedEggs = Convert.ToDecimal(GetCurrentColumnValue("MinorCrackedEggs"));

if (GetCurrentColumnValue("MajorCrackedEggs") != null)
    majorCrackedEggs = Convert.ToDecimal(GetCurrentColumnValue("MajorCrackedEggs"));

if (GetCurrentColumnValue("ThinShellEggs") != null)
    thinShellEggs = Convert.ToDecimal(GetCurrentColumnValue("ThinShellEggs"));

if (GetCurrentColumnValue("OtherEggs") != null)
    otherEggs = Convert.ToDecimal(GetCurrentColumnValue("OtherEggs"));

if (GetCurrentColumnValue("WholeEggs") != null)
    wholeEggs = Convert.ToDecimal(GetCurrentColumnValue("WholeEggs"));

if (GetCurrentColumnValue("BrokenEggs") != null)
    brokenEggs = Convert.ToDecimal(GetCurrentColumnValue("BrokenEggs"));

if (GetCurrentColumnValue("SmallEggs") != null)
    smallEggs = Convert.ToDecimal(GetCurrentColumnValue("SmallEggs"));

if (GetCurrentColumnValue("OverWeightEggs") != null)
    overWeightEggs = Convert.ToDecimal(GetCurrentColumnValue("OverWeightEggs"));

if (GetCurrentColumnValue("DirtyEggs") != null)
    dirtyEggs = Convert.ToDecimal(GetCurrentColumnValue("DirtyEggs"));

if (GetCurrentColumnValue("DeformityEggs") != null)
    deformityEggs = Convert.ToDecimal(GetCurrentColumnValue("DeformityEggs"));

if (GetCurrentColumnValue("CrackedEggs") != null)
    crackedEggs = Convert.ToDecimal(GetCurrentColumnValue("CrackedEggs"));

if (GetCurrentColumnValue("DoubleYolkEggs") != null)
    doubleYolkEggs = Convert.ToDecimal(GetCurrentColumnValue("DoubleYolkEggs"));

if (GetCurrentColumnValue("DestroyedEggs") != null)
    destroyedEggs = Convert.ToDecimal(GetCurrentColumnValue("DestroyedEggs"));

if (GetCurrentColumnValue("TotalUnHatch") != null)
    totalUnHatch = Convert.ToDecimal(GetCurrentColumnValue("TotalUnHatch"));

if (GetCurrentColumnValue("RecEggs") != null)
    recEggs = Convert.ToDecimal(GetCurrentColumnValue("RecEggs"));
// --- Add to group sum ---
groupSumSpecialEggs += (softShellEggs + minorCrackedEggs + majorCrackedEggs + thinShellEggs +
                        otherEggs + wholeEggs + brokenEggs + smallEggs + overWeightEggs +
                        dirtyEggs + deformityEggs + crackedEggs + doubleYolkEggs + destroyedEggs);

// --- Add IIf logic ---
if (recEggs != 0)
    TotalPercGroup += (totalUnHatch * 100.0m / recEggs);


groupTotalSumSpecialEggs = groupSumSpecialEggs + TotalPercGroup 
// -- new logic for Hatching eggs
decimal HatchingEggs = 0;
decimal RecEggs = 0;

// --- HatchingEggs ---
if (GetCurrentColumnValue("HatchingEggs") != null)
    HatchingEggs += Convert.ToDecimal(GetCurrentColumnValue("HatchingEggs"));

// --- RecEggs ---
if (GetCurrentColumnValue("RecEggs") != null)
    RecEggs += Convert.ToDecimal(GetCurrentColumnValue("RecEggs"));

// --- Percentage calculation ---
if (RecEggs != 0)
    TotalpercentageHatchingEggsGroup = (HatchingEggs * 100m) / RecEggs;


}

private void xrTableCell88_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
      xrTableCell88.Text = TotalSpecialEggsReport.ToString("0");
      TotalSpecialEggsReport  = 0; // reset for next group
}

private void xrTableCell64_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
      xrTableCell64.Text = groupTotalSumSpecialEggs.ToString("0");
      groupTotalSumSpecialEggs = 0; // reset for next group

}

private void xrTableCell54_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    // --- Declare values ---
decimal hatchingEggs = 0;
decimal recEggs = 0;

// --- HatchingEggs ---
if (GetCurrentColumnValue("HatchingEggs") != null)
    hatchingEggs = Convert.ToDecimal(GetCurrentColumnValue("HatchingEggs"));

// --- RecEggs ---
if (GetCurrentColumnValue("RecEggs") != null)
    recEggs = Convert.ToDecimal(GetCurrentColumnValue("RecEggs"));

// --- Equation ---
decimal percentage = 0;
if (recEggs != 0)
    percentage = (hatchingEggs * 100m) / recEggs;
    TotalhatchingEggsReportPerc += percentage 

// --- Assign result to cell ---
XRTableCell cell = sender as XRTableCell;
cell.Text = percentage.ToString("0.00"); // 2 decimals

}

private void xrTableCell90_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
      xrTableCell90.Text = TotalpercentageHatchingEggsGroup.ToString("0");
      TotalpercentageHatchingEggsGroup  = 0; // reset for next group

}

